{
  "domain_analysis": {
    "business_context": "A global logistics platform introducing real-time driver earnings breakdown (base pay, per-delivery bonus, tips, deductions) across three jurisdictions with materially different labor classifications, legal requirements, and institutional approval processes.",
    "bounded_context": "Driver Compensation & Earnings Visibility",
    "ubiquitous_language": [
      { "term": "Base Pay", "definition": "The fixed compensation component for a delivery task before bonuses, tips, or deductions. For employees (CA), this must meet or exceed minimum wage guarantees. For contractors (Indonesia), this is the agreed service fee." },
      { "term": "Per-Delivery Bonus", "definition": "Variable compensation tied to completing individual deliveries, potentially influenced by surge pricing, distance, or time-of-day multipliers." },
      { "term": "Tip", "definition": "Gratuity paid by the customer to the driver. Must be displayed separately and never commingled with base pay or bonuses. In California, tips cannot offset minimum wage obligations." },
      { "term": "Deduction", "definition": "Any amount subtracted from gross earnings, including platform fees, equipment charges, tax withholdings, or social insurance contributions. The composition and legal constraints on deductions vary by jurisdiction and employment classification." },
      { "term": "Driver Classification", "definition": "The legal employment status of the driver — employee (California under AB5, Germany) or independent contractor (Indonesia) — which determines what earnings components exist, what must be disclosed, and what approval processes apply." },
      { "term": "Earnings Breakdown", "definition": "The itemized, real-time view of a driver's compensation for a given period, decomposed into base pay, bonuses, tips, and deductions." },
      { "term": "Works Council (Betriebsrat)", "definition": "A German co-determination body with legal authority to approve or block changes to compensation display systems before rollout. Their approval is a hard prerequisite, not a courtesy." },
      { "term": "Wage Transparency", "definition": "The legal obligation (in some jurisdictions) to disclose compensation components to workers in a clear, timely, and itemized manner." },
      { "term": "Net Earnings", "definition": "The final amount payable to the driver after all deductions are applied to gross earnings." },
      { "term": "Gross Earnings", "definition": "The sum of base pay, per-delivery bonuses, and tips before any deductions." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "Tips must always be displayed as a separate line item and must never be commingled with, or offset against, base pay or bonuses in any jurisdiction.",
      "invariant": true,
      "invariant_justification": "Commingling tips with base pay is illegal in California (Labor Code §351) and violates fundamental pay transparency principles. A system that merges these is producing corrupt/misleading compensation data.",
      "testable_assertion": "In every earnings breakdown rendered to a driver, tips appear as a distinct line item with its own label and amount, separate from base pay and bonus amounts."
    },
    {
      "id": "BR-2",
      "rule": "Every deduction must be individually itemized with a description and amount. No opaque aggregate 'total deductions' without line-item detail.",
      "invariant": true,
      "invariant_justification": "An earnings breakdown that hides the composition of deductions is not transparent — it defeats the purpose of the feature and violates California wage transparency requirements. The data integrity of the breakdown depends on full itemization.",
      "testable_assertion": "For any earnings breakdown containing deductions, each deduction is listed with a human-readable description and its individual amount, and the sum of individual deductions equals the total deductions displayed."
    },
    {
      "id": "BR-3",
      "rule": "In California, the earnings breakdown must include all legally mandated wage statement components (gross wages, total hours, net wages, all deductions, applicable rates) and must be available in real time.",
      "invariant": false,
      "invariant_justification": "This is a jurisdiction-specific legal compliance policy. The specific required fields could change if California amends its Labor Code. A VP cannot change it, but a legislature can.",
      "testable_assertion": "When a driver's jurisdiction is California, the earnings breakdown includes: gross wages, net wages, total hours worked, hourly rate, and each deduction with description — all updated within the platform's real-time SLA."
    },
    {
      "id": "BR-4",
      "rule": "The Germany earnings breakdown feature must not be deployed to German drivers until explicit Works Council (Betriebsrat) approval is recorded in the system.",
      "invariant": true,
      "invariant_justification": "Deploying a compensation display system in Germany without Works Council approval violates the Betriebsverfassungsgesetz (Works Constitution Act). This is not a preference — it is a legal gate. Bypassing it puts the company in violation of German co-determination law and could result in injunctions.",
      "testable_assertion": "The system enforces a feature gate for Germany that requires a recorded Works Council approval event before the earnings breakdown is visible to any German driver."
    },
    {
      "id": "BR-5",
      "rule": "The earnings breakdown must reflect the driver's correct employment classification (employee vs. independent contractor) and show only compensation components valid for that classification.",
      "invariant": true,
      "invariant_justification": "Displaying employee-style deductions (e.g., tax withholding, social insurance) to an independent contractor — or vice versa — misrepresents the legal relationship and could create legal liability (e.g., evidence of misclassification). The data model is corrupt if classification and components are mismatched.",
      "testable_assertion": "A California driver (employee) sees withholding deductions and hourly rate; an Indonesian driver (contractor) does not see employer tax withholdings or hourly wage calculations. Each classification maps to a defined set of valid earnings components."
    },
    {
      "id": "BR-6",
      "rule": "Net earnings displayed must always equal gross earnings minus the sum of all itemized deductions. The arithmetic must be verifiable by the driver.",
      "invariant": true,
      "invariant_justification": "If displayed net earnings do not reconcile to the itemized components, the system is producing inconsistent financial data. This is a data integrity invariant.",
      "testable_assertion": "For every earnings breakdown: base_pay + per_delivery_bonus + tips - sum(deductions) == net_earnings, with no rounding discrepancy exceeding the smallest currency unit."
    },
    {
      "id": "BR-7",
      "rule": "In California, tips must not be credited toward meeting minimum wage obligations. Base pay alone (or base pay plus bonuses, per local law) must meet or exceed the applicable minimum wage for hours worked.",
      "invariant": false,
      "invariant_justification": "This is a California-specific labor law policy. The threshold and rules could be amended legislatively, but the platform cannot override it while the law stands.",
      "testable_assertion": "For California drivers, a validation check confirms that (base_pay + eligible_bonuses) / hours_worked >= california_minimum_wage, calculated without including tips."
    },
    {
      "id": "BR-8",
      "rule": "Earnings data must be scoped per-driver with no cross-driver leakage. A driver may only view their own earnings breakdown.",
      "invariant": true,
      "invariant_justification": "Cross-driver earnings visibility is a data privacy violation in all three jurisdictions and corrupts the trust model of the system.",
      "testable_assertion": "Any API call or UI request for earnings breakdown is authenticated and authorized to return data only for the requesting driver's own records."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A driver in California completes a delivery",
      "when": "They view their earnings breakdown",
      "then": "They see itemized base pay (with hourly rate and hours), per-delivery bonus, tips (separate line), all deductions individually listed, gross earnings, and net earnings — all updated in real time."
    },
    {
      "id": "AC-2",
      "given": "The Works Council in Germany has NOT yet approved the earnings display feature",
      "when": "A German driver attempts to access the earnings breakdown",
      "then": "The feature is not visible or accessible; the driver sees no earnings breakdown UI and receives no partial data."
    },
    {
      "id": "AC-3",
      "given": "The Works Council in Germany HAS approved the earnings display feature",
      "when": "A German driver views their earnings breakdown",
      "then": "They see an itemized breakdown appropriate to their employee classification under German labor law, including social insurance contributions and tax withholdings as deductions."
    },
    {
      "id": "AC-4",
      "given": "An independent contractor driver in Indonesia completes a delivery",
      "when": "They view their earnings breakdown",
      "then": "They see base pay (service fee), per-delivery bonus, tips (separate line), platform fee deductions, and net earnings — with no employee-specific components like tax withholding or hourly wage rate."
    },
    {
      "id": "AC-5",
      "given": "A driver in any jurisdiction views their earnings breakdown",
      "when": "The breakdown is rendered",
      "then": "Net earnings equals gross earnings minus the sum of all displayed deductions, verifiable to the smallest currency unit."
    },
    {
      "id": "AC-6",
      "given": "A driver is authenticated",
      "when": "They request earnings data",
      "then": "Only their own earnings are returned; no other driver's data is accessible or leaked."
    },
    {
      "id": "AC-7",
      "given": "A California driver has earned tips during a shift",
      "when": "The system calculates minimum wage compliance",
      "then": "Tips are excluded from the minimum wage calculation; only base pay and eligible bonuses are used."
    }
  ],

  "edge_cases": [
    {
      "scenario": "A driver relocates from Indonesia to California mid-employment, changing classification from contractor to employee.",
      "expected_behavior": "The earnings breakdown must switch to the California employee template from the effective date of reclassification. Historical earnings under the contractor model remain displayed under the contractor format for their respective periods. No retroactive reformatting."
    },
    {
      "scenario": "A California driver completes a delivery but the tip is added by the customer 30 minutes later.",
      "expected_behavior": "The earnings breakdown updates in real time to reflect the late-arriving tip as a separate line item. The net earnings recalculates. The breakdown remains arithmetically consistent at every point in time — before and after the tip arrives."
    },
    {
      "scenario": "Germany's Works Council approval is revoked after initial rollout.",
      "expected_behavior": "The feature gate re-engages. German drivers lose access to the earnings breakdown immediately. Historical data access policy should be defined per legal counsel — escalation required."
    },
    {
      "scenario": "A deduction results in negative net earnings for a delivery (e.g., equipment charge exceeds earnings).",
      "expected_behavior": "The breakdown honestly displays the negative net earnings. The system does not hide or zero-floor the amount. In California, additional validation must ensure this does not violate minimum wage laws for the pay period."
    },
    {
      "scenario": "Platform fee structure changes mid-shift in Indonesia.",
      "expected_behavior": "Deliveries completed before the change show the old fee; deliveries after show the new fee. Each deduction line item reflects the rate applicable at the time of that specific delivery."
    },
    {
      "scenario": "A driver has zero deliveries in a period but has deductions (e.g., recurring equipment rental).",
      "expected_behavior": "The earnings breakdown displays zero base pay, zero bonuses, zero tips, the applicable deductions, and a negative net earnings figure. The system does not suppress the breakdown for zero-delivery periods."
    },
    {
      "scenario": "Currency display for a driver operating in a jurisdiction where the platform pays in a different currency than the local one.",
      "expected_behavior": "Earnings are displayed in the currency the driver is actually paid in. If conversion applies, the exchange rate and conversion must be shown as a transparent line item, not hidden."
    }
  ],

  "business_impact": {
    "financial": "Compliance failure in California exposes the platform to Labor Code §226 penalties ($250 per employee per violation for initial, $1,000 for subsequent). German deployment without Works Council approval risks injunctions and fines. Correct implementation builds driver trust, potentially reducing churn and recruitment costs.",
    "operational": "Requires jurisdiction-aware feature gating (Germany Works Council gate), classification-aware template rendering, and real-time earnings aggregation. The system must support at least three distinct breakdown templates and a legal approval workflow. Ongoing maintenance includes tracking legislative changes across jurisdictions.",
    "user": "Drivers gain visibility into how their pay is calculated, building trust and reducing support tickets about pay discrepancies. In California, this is a legal right. In Indonesia, this is a competitive differentiator for driver retention even though not legally required.",
    "risk": "HIGH — Misclassification signal (showing employee deductions to contractors) creates litigation risk. Deploying in Germany without Works Council approval is a compliance violation. Incorrect tip handling in California is a wage theft exposure. Multi-jurisdiction rollout amplifies the blast radius of any domain modeling error.",
    "stakeholders_affected": [
      { "group": "Drivers (California)", "impact": "Legally entitled to this information. Failure to provide it accurately is a wage statement violation." },
      { "group": "Drivers (Germany)", "impact": "Cannot receive the feature until Works Council approves. Must not see partial or unapproved versions." },
      { "group": "Drivers (Indonesia)", "impact": "Receive transparency as a benefit, not a right. Breakdown must reflect contractor status accurately to avoid misclassification risk." },
      { "group": "Works Council (Germany)", "impact": "Must be engaged as a decision-making stakeholder with veto power over the German rollout. Not advisory — binding." },
      { "group": "Legal/Compliance Team", "impact": "Owns the jurisdiction-specific rules mapping. Must validate each template and be notified of any changes to deduction logic." },
      { "group": "Finance/Payroll", "impact": "Earnings breakdown must reconcile exactly with actual payroll records. Any discrepancy between displayed and paid amounts is a major liability." },
      { "group": "Product/Engineering", "impact": "Must build jurisdiction-aware, classification-aware rendering with a legal approval gate — significantly more complex than a single global feature." }
    ]
  },

  "confidence": {
    "level": 52,
    "reasoning": "The spec is underspecified in several critical dimensions: (1) no mention of Works Council engagement status or timeline for Germany, (2) no guidance on what happens when legal approval is revoked, (3) no specification of which German compensation components require display, (4) the phrase 'real time' is undefined (seconds? minutes? per-delivery?), (5) California AB5 classification is stated but the specific wage statement requirements under Labor Code §226 are not enumerated in the spec. Multiple jurisdictions with different legal frameworks and an ambiguous 'real time' requirement create significant risk of incorrect implementation.",
    "high_confidence_areas": [
      "Tips must be a separate line item in all jurisdictions",
      "Net earnings must reconcile arithmetically with displayed components",
      "Germany requires Works Council approval before deployment",
      "Driver classification determines valid earnings components",
      "Data must be scoped per-driver with no leakage"
    ],
    "low_confidence_areas": [
      "Exact set of mandatory fields for California wage statement compliance",
      "Which specific German compensation components must be displayed post-Works Council approval",
      "Definition of 'real time' — latency SLA is unspecified",
      "Whether historical earnings data access is affected by the Germany Works Council gate",
      "How the platform handles multi-jurisdiction drivers or jurisdiction transitions"
    ],
    "assumptions": [
      "California drivers are classified as employees under AB5 as stated — no reclassification disputes are pending",
      "The platform already has jurisdiction and classification data for each driver",
      "Tips are received through the platform (not cash) and are trackable",
      "The Works Council approval process is binary (approved/not approved) with no partial approval state",
      "Each driver operates in exactly one jurisdiction at a time"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "'Real time' is undefined. Does this mean per-delivery update, sub-second latency, per-shift aggregation, or something else? The answer materially affects architecture (event-driven vs. polling vs. batch) and compliance (California requires timely wage statements but the spec doesn't define the SLA).",
      "affected_stakeholders": ["Drivers (all jurisdictions)", "Engineering", "Legal/Compliance"],
      "options": ["Define real-time as 'updated within 60 seconds of delivery completion'", "Define as 'updated per-delivery, visible before next delivery accepted'", "Define as 'updated per pay period with live running total'"],
      "recommendation": "Define as 'updated within 60 seconds of each delivery event (completion, tip receipt, deduction applied)' to satisfy California transparency requirements without over-engineering."
    },
    {
      "type": "missing_context",
      "description": "The spec does not address what happens if Germany's Works Council rejects or revokes approval. Is there a fallback experience? Is historical data still accessible? Does the feature remain gated indefinitely?",
      "affected_stakeholders": ["Drivers (Germany)", "Works Council", "Legal/Compliance", "Product"],
      "options": ["Feature remains permanently gated until approval", "Provide a reduced/alternative view that doesn't require approval", "Escalate to legal for Works Council engagement strategy"],
      "recommendation": "Feature remains gated until approval. No partial or alternative view should be built without explicit Works Council consultation, as even a 'reduced' view may trigger co-determination rights."
    },
    {
      "type": "ambiguity",
      "description": "The spec does not enumerate the exact fields required for California wage statement compliance under Labor Code §226. Missing mandatory fields could result in per-violation penalties. Legal review of the specific field requirements is needed before implementation.",
      "affected_stakeholders": ["Drivers (California)", "Legal/Compliance", "Finance/Payroll"],
      "options": ["Engineering team researches §226 requirements independently", "Legal team provides a definitive field list before implementation begins", "Ship a superset of all possible fields and refine later"],
      "recommendation": "Legal team must provide the definitive California wage statement field list as a prerequisite before the California template is implemented. Do not ship without legal sign-off."
    },
    {
      "type": "missing_context",
      "description": "No specification of how earnings breakdown reconciles with actual payroll. If the displayed breakdown diverges from what payroll actually pays, the platform has a worse problem than no transparency. Is the earnings breakdown sourced from payroll data, or calculated independently?",
      "affected_stakeholders": ["Finance/Payroll", "Drivers (all jurisdictions)", "Legal/Compliance"],
      "options": ["Earnings breakdown is a read-only view of payroll system data (single source of truth)", "Earnings breakdown is independently calculated from delivery events and must be reconciled with payroll"],
      "recommendation": "Earnings breakdown must be a projection of the same data that drives actual payroll. Single source of truth. Independent calculation creates reconciliation drift and liability."
    }
  ],

  "rejection_reasons": []
}

